+    #[test]
+    fn btrfs_write_rename_over_same_inode_hardlink_is_noop() {
+        let (fs, cx) = open_writable_btrfs();
+        let ops: &dyn FsOps = &fs;
+
+        let file = ops
+            .create(
+                &cx,
+                &mut RequestScope::empty(),
+                InodeNumber(1),
+                OsStr::new("original.txt"),
+                0o644,
+                0,
+                0,
+            )
+            .unwrap();
+        ops.write(
+            &cx,
+            &mut RequestScope::empty(),
+            file.ino,
+            0,
+            b"same inode rename",
+        )
+        .unwrap();
+        ops.link(
+            &cx,
+            &mut RequestScope::empty(),
+            file.ino,
+            InodeNumber(1),
+            OsStr::new("alias.txt"),
+        )
+        .unwrap();
+
+        ops.rename(
+            &cx,
+            &mut RequestScope::empty(),
+            InodeNumber(1),
+            OsStr::new("original.txt"),
+            InodeNumber(1),
+            OsStr::new("alias.txt"),
+        )
+        .unwrap();
+
+        let alias = ops
+            .lookup(
+                &cx,
+                &mut RequestScope::empty(),
+                InodeNumber(1),
+                OsStr::new("alias.txt"),
+            )
+            .unwrap();
+        assert_eq!(alias.ino, file.ino);
+
+        let original_err = ops
+            .lookup(
+                &cx,
+                &mut RequestScope::empty(),
+                InodeNumber(1),
+                OsStr::new("original.txt"),
+            )
+            .unwrap_err();
+        assert_eq!(original_err.to_errno(), libc::ENOENT);
+
+        let after = ops
+            .getattr(&cx, &mut RequestScope::empty(), file.ino)
+            .unwrap();
+        assert_eq!(after.nlink, 1);
+
+        let data = ops
+            .read(&cx, &mut RequestScope::empty(), file.ino, 0, 4096)
+            .unwrap();
+        assert_eq!(data, b"same inode rename");
+    }
